import React, { useState } from "react";

/*
  =========================================================
  InvestigationLogs.jsx
  =========================================================
  Context:
  - Technician audit & investigation history
  - Backend (future):
      GET /api/investigations/logs
      GET /api/investigations/:caseId/timeline
      GET /api/investigations/:caseId/evidence
*/

const InvestigationLogs = () => {
  /* =====================================================
     Dummy Backend Data
     ===================================================== */
  const logsData = [
    {
      caseId: "CASE-9001",
      systemId: "SYS-10234",
      technician: "Indra K",
      aiVerdict: "Hardware Failure",
      finalVerdict: "Confirmed Hardware Failure",
      evidenceCount: 4,
      status: "Closed",
      severity: "Critical",
      lastUpdated: "2026-01-16 14:30",
      compliance: {
        evidence: true,
        notes: true,
        confidence: true,
        admin: true,
      },
      timeline: [
        { time: "2026-01-14 09:10", actor: "AI Engine", event: "AI Verdict Generated" },
        { time: "2026-01-14 09:20", actor: "System", event: "Technician Assigned" },
        { time: "2026-01-15 10:30", actor: "Indra K", event: "Investigation Notes Added" },
        { time: "2026-01-15 11:00", actor: "Indra K", event: "Evidence Uploaded (logs.zip)" },
        { time: "2026-01-16 14:30", actor: "Indra K", event: "Final Verdict Confirmed" },
      ],
      evidence: [
        { name: "disk-logs.zip", type: "Logs", by: "Indra K", time: "2026-01-15 11:00" },
        { name: "iostat.png", type: "Image", by: "Indra K", time: "2026-01-15 11:05" },
      ],
    },
    {
      caseId: "CASE-9002",
      systemId: "SYS-10241",
      technician: "Rahul S",
      aiVerdict: "Security Anomaly",
      finalVerdict: "Under Investigation",
      evidenceCount: 1,
      status: "In Progress",
      severity: "High",
      lastUpdated: "2026-01-16 09:10",
      compliance: {
        evidence: true,
        notes: false,
        confidence: true,
        admin: false,
      },
      timeline: [
        { time: "2026-01-16 08:30", actor: "AI Engine", event: "AI Verdict Generated" },
        { time: "2026-01-16 08:40", actor: "System", event: "Technician Assigned" },
      ],
      evidence: [
        { name: "auth-log.txt", type: "Log", by: "Rahul S", time: "2026-01-16 09:00" },
      ],
    },
  ];

  /* =====================================================
     UI State
     ===================================================== */
  const [search, setSearch] = useState("");
  const [selectedLog, setSelectedLog] = useState(null);

  /* =====================================================
     Filters
     ===================================================== */
  const filteredLogs = logsData.filter(
    (log) =>
      log.systemId.toLowerCase().includes(search.toLowerCase()) ||
      log.technician.toLowerCase().includes(search.toLowerCase())
  );

  /* =====================================================
     UI Helpers
     ===================================================== */
  const statusStyle = {
    Closed: "bg-green-100 text-green-700",
    "In Progress": "bg-blue-100 text-blue-700",
    Pending: "bg-gray-100 text-gray-700",
  };

  const severityStyle = {
    Critical: "bg-red-100 text-red-700",
    High: "bg-orange-100 text-orange-700",
    Medium: "bg-yellow-100 text-yellow-700",
  };

  /* =====================================================
     RENDER
     ===================================================== */
  return (
    <div className="space-y-6">

      {/* =================================================
         1. PAGE HEADER
         ================================================= */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-semibold text-gray-900">
            Investigation Logs
          </h1>
          <p className="text-sm text-gray-500">
            Technician investigation history and audit trail
          </p>
        </div>

        <input
          placeholder="Search System ID or Technician"
          className="border rounded-md px-3 py-2 text-sm"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      {/* =================================================
         2. INVESTIGATION LOG TABLE
         ================================================= */}
      <div className="bg-white border rounded-lg overflow-hidden">
        <table className="w-full text-sm">
          <thead className="bg-gray-50 text-gray-600">
            <tr>
              <th className="px-4 py-3 text-left">Case ID</th>
              <th className="px-4 py-3 text-left">System ID</th>
              <th className="px-4 py-3">Technician</th>
              <th className="px-4 py-3">AI Verdict</th>
              <th className="px-4 py-3">Final Verdict</th>
              <th className="px-4 py-3">Evidence</th>
              <th className="px-4 py-3">Status</th>
              <th className="px-4 py-3">Last Updated</th>
              <th className="px-4 py-3">Action</th>
            </tr>
          </thead>

          <tbody>
            {filteredLogs.map((log) => (
              <tr key={log.caseId} className="border-t hover:bg-gray-50">
                <td className="px-4 py-3 font-medium">{log.caseId}</td>

                <td className="px-4 py-3 text-blue-600 font-medium cursor-pointer">
                  {log.systemId}
                </td>

                <td className="px-4 py-3 text-center">{log.technician}</td>

                <td className="px-4 py-3 text-center">{log.aiVerdict}</td>

                <td className="px-4 py-3 text-center">{log.finalVerdict}</td>

                <td className="px-4 py-3 text-center">
                  {log.evidenceCount}
                </td>

                <td className="px-4 py-3 text-center">
                  <span
                    className={`px-2 py-1 rounded-full text-xs font-medium ${statusStyle[log.status]}`}
                  >
                    {log.status}
                  </span>
                </td>

                <td className="px-4 py-3 text-center">
                  {log.lastUpdated}
                </td>

                <td className="px-4 py-3 text-center">
                  <button
                    onClick={() => setSelectedLog(log)}
                    className="text-blue-600 hover:underline"
                  >
                    View Timeline
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* =================================================
         3–4–5. TIMELINE DRAWER + EVIDENCE + COMPLIANCE
         ================================================= */}
      {selectedLog && (
        <div className="border rounded-lg p-4 bg-white">
          <div className="flex justify-between items-center mb-3">
            <h2 className="font-semibold text-lg">
              Case Timeline — {selectedLog.caseId}
            </h2>
            <button
              onClick={() => setSelectedLog(null)}
              className="text-sm text-gray-500 hover:underline"
            >
              Close
            </button>
          </div>

          {/* Timeline */}
          <ul className="space-y-2 text-sm mb-4">
            {selectedLog.timeline.map((t, idx) => (
              <li key={idx} className="flex gap-4">
                <span className="text-gray-500">{t.time}</span>
                <span className="font-medium">{t.actor}:</span>
                <span>{t.event}</span>
              </li>
            ))}
          </ul>

          {/* Evidence Summary */}
          <h3 className="font-medium mb-2">Evidence Summary</h3>
          <ul className="text-sm mb-4">
            {selectedLog.evidence.map((e, idx) => (
              <li key={idx}>
                {e.name} ({e.type}) — uploaded by {e.by} at {e.time}
              </li>
            ))}
          </ul>

          {/* Compliance Indicators */}
          <h3 className="font-medium mb-2">Compliance Indicators</h3>
          <div className="flex gap-2 text-xs">
            {selectedLog.compliance.evidence && (
              <Badge label="Evidence Retained" />
            )}
            {selectedLog.compliance.notes && (
              <Badge label="Notes Present" />
            )}
            {selectedLog.compliance.confidence && (
              <Badge label="AI Confidence Logged" />
            )}
            {selectedLog.compliance.admin && (
              <Badge label="Admin Notified" />
            )}
          </div>
        </div>
      )}
    </div>
  );
};

/* =====================================================
   Reusable Badge
   ===================================================== */
const Badge = ({ label }) => (
  <span className="px-2 py-1 rounded-full bg-green-100 text-green-700">
    {label}
  </span>
);

export default InvestigationLogs;
